package net.postchain.rell.codegen.kotlin

import net.postchain.rell.codegen.deps.ClassName
import net.postchain.rell.codegen.document.AbstractDocument

class KotlinDocument(val packageName: String, moduleName: String) : AbstractDocument(
    "// Generated by kotlin generator",
    formatPackageString(packageName, moduleName)
) {
    override fun importMap(className: ClassName) = "import ${className.toPackageName(packageName)}"
}

private fun formatPackageString(packageName: String, moduleName: String) =
    if (moduleName.isBlank()) "package $packageName" else "package $packageName.$moduleName"